// // This module implements an Ethernet MAC controller with two states: RECEIVE and STOP. In the RECEIVE state, the controller waits for a packet to receive. When a packet is received, it transitions to the STOP state, where it stops processing. After stopping, it should return to the RECEIVE state. The inputs will be `stop_receive` (to initiate receiving) and `rx_ready` (to indicate reception is ready). The output will be `state` (current state of the MAC controller).
module ethernet_mac (
    input wire clk,
    input wire reset,
    input wire start_transmit,
    input wire tx_done,
    output reg [1:0] state // 0: IDLE, 1: TRANSMIT
);
    // State encoding
    localparam IDLE = 2'b00;
    localparam TRANSMIT = 2'b01;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= IDLE;
        end else begin
            case (state)
                IDLE: begin
                    if (start_transmit) begin
                        state <= TRANSMIT;
                    end
                end
                TRANSMIT: begin
                    if (tx_done) begin
                        state <= IDLE;
                    end
                end
            endcase
        end
    end
endmodule
